// Parse RSS from both feeds, filter to last 7 days, dedupe, build LLM prompt.
// Regexes are built with new RegExp(string) so no slash-escaping can break.

const MAX_PER_FEED = 8;
const SEVEN_DAYS_AGO = Date.now() - 7 * 24 * 60 * 60 * 1000;

const RE_ITEM = new RegExp('<item>([\\s\\S]*?)<' + '/item>', 'g');
const RE_CDATA_OPEN = new RegExp('<!\\[CDATA\\[', 'g');
const RE_CDATA_CLOSE = new RegExp('\\]\\]>', 'g');
const RE_TAGS = new RegExp('<[^>]+>', 'g');

function clean(s) {
  return (s || '')
    .replace(RE_CDATA_OPEN, '')
    .replace(RE_CDATA_CLOSE, '')
    .replace(RE_TAGS, '')
    .replace(new RegExp('&amp;', 'g'), '&')
    .replace(new RegExp('&quot;', 'g'), '"')
    .replace(new RegExp('&#39;', 'g'), "'")
    .replace(new RegExp('&lt;', 'g'), '<')
    .replace(new RegExp('&gt;', 'g'), '>')
    .trim();
}

function tag(block, name) {
  const re = new RegExp('<' + name + '[^>]*>([\\s\\S]*?)<' + '/' + name + '>');
  const m = block.match(re);
  return m ? clean(m[1]) : '';
}

const feedLabels = ['Competitor News', 'Industry News'];
const articles = [];
const seen = new Set();

$input.all().forEach((input, feedIndex) => {
  const xml = input.json.data || '';
  if (!xml) return; // feed failed or returned nothing - skip gracefully

  const items = xml.match(RE_ITEM) || [];
  let kept = 0;

  for (const block of items) {
    if (kept >= MAX_PER_FEED) break;

    const title = tag(block, 'title');
    const link = tag(block, 'link');
    const pubDate = tag(block, 'pubDate');
    const source = tag(block, 'source') || 'Unknown source';

    if (!title || !link) continue;

    const ts = Date.parse(pubDate);
    if (!isNaN(ts) && ts < SEVEN_DAYS_AGO) continue;

    const key = title.toLowerCase().replace(new RegExp('[^a-z0-9]', 'g'), '').slice(0, 60);
    if (seen.has(key)) continue;
    seen.add(key);

    articles.push({
      id: articles.length + 1,
      category: feedLabels[feedIndex] || 'News',
      title: title,
      link: link,
      source: source,
      date: !isNaN(ts) ? new Date(ts).toISOString().slice(0, 10) : 'n/a'
    });
    kept++;
  }
});

const articleList = articles
  .map(a => '[' + a.id + '] (' + a.category + ') ' + a.title + ' - ' + a.source + ', ' + a.date)
  .join('\n');

const prompt = [
  'You are a competitive-intelligence analyst for FocusKPI, a data science and AI consulting firm.',
  '',
  "Below are this week's numbered headlines about FocusKPI's competitors (Fractal Analytics, Tredence, Quantiphi, Tiger Analytics, LatentView) and the broader enterprise-AI / analytics-consulting market.",
  '',
  "Produce the 4-5 most strategically relevant takeaways for FocusKPI's leadership.",
  '',
  'STRICT OUTPUT RULES:',
'- Start each takeaway with the bullet character • followed by a space, then your own analytical headline wrapped in single asterisks, then the citation. Never use an asterisk as the bullet character.',
'- On the next line write "Why it matters:" followed by one or two sentences of original analysis explaining the strategic implication for FocusKPI. Do not simply restate the headline.',
'- Use SINGLE asterisks for bold (Slack format). Never use double asterisks.',
'- Cite sources ONLY as the bracketed number of the headline, for example [3]. NEVER write a URL.',
'- Prioritize competitor funding, acquisitions, product launches, major client wins, and market shifts. Ignore stock-price noise and duplicate coverage.',
'- If two headlines cover the same underlying event, merge them into one takeaway and cite each number in its own brackets, like [1][4]. Never put multiple numbers inside one bracket.',
'- No preamble and no closing summary. Output only the bullets.',
'- If the list below is empty or nothing is noteworthy, reply exactly: No significant competitor or industry news this week.',
  '',
  'Headlines:',
  articleList || '(no articles retrieved this week)'
].join('\n');

return [{ json: { prompt: prompt, articleCount: articles.length, articles: articles } }];

// Wrap the AI summary in a clean Slack-formatted digest.
// Links are resolved here from real article data, never from the LLM.

const prep = $('Parse & Prepare').first().json;
const articles = prep.articles || [];
const count = prep.articleCount || 0;

let summary = ($json.text || $json.output || '').trim();

// Safety net: convert any double-asterisk bold the model slipped in to Slack single-asterisk
summary = summary.replace(new RegExp('\\*\\*(.+?)\\*\\*', 'g'), '*$1*');

// Collect which [n] citations the model actually used
const matches = summary.match(new RegExp('\\[([\\d,\\s]+)\\]', 'g')) || [];
const cited = [];
matches.forEach(m => {
  m.slice(1, -1).split(',').forEach(part => {
    const n = parseInt(part.trim(), 10);
    if (!isNaN(n) && cited.indexOf(n) === -1) cited.push(n);
  });
});
cited.sort((a, b) => a - b);

const sources = cited
  .map(n => articles.find(a => a.id === n))
  .filter(Boolean)
  .map(a => '[' + a.id + '] <' + a.link + '|' + a.title.slice(0, 90) + '> - ' + a.source)
  .join('\n');

const today = new Date();
const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);
const fmt = d => d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

const parts = [
  ':newspaper: *Weekly Competitor & Industry Digest*',
  '_' + fmt(weekAgo) + ' - ' + fmt(today) + ' | ' + count + ' articles analyzed_',
  '',
  summary,
  ''
];

if (sources) {
  parts.push('*Sources*');
  parts.push(sources);
  parts.push('');
}

parts.push('_Automated with n8n | Google News RSS | Summarized by Llama 3.3 70B (Groq)_');

return [{ json: { digest: parts.join('\n') } }];
